import java.util.Arrays;

public class Main {
    public static int maxScore(int[] nums) {
        Arrays.sort(nums);
        int n = nums.length / 2;
        int[] dp = new int[n + 1];
        dp[0] = 0;
        for (int i = 1; i <= n; i++) {
            int max = 0;
            for (int j = i - 1; j >= 0; j--) {
                max = Math.max(max, dp[j] + i * gcd(nums[2 * j + 1], nums[2 * i - 1]));
            }
            dp[i] = max;
        }
        return dp[n];
    }

    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }

    public static void main(String[] args) {
        int[] nums = {1, 2, 3, 4, 5, 6};
        System.out.println(maxScore(nums));
    }
}
```

